escaped_lines = []
y_offset = 40
for line in ascii_text.strip().split("\n"):
    # Clean non-breaking spaces or regular spaces and escape XML entities
    escaped_line = html.escape(line).replace(" ", "&#160;").replace("\xa0", "&#160;")
    escaped_lines.append(f'<tspan x="25" y="{y_offset:.1f}">{escaped_line}</tspan>')
    y_offset += 4.9

with open("/Users/macbook/Desktop/Cardano04class/scratch/escaped_tspan_v3.txt", "w") as f:
    f.write("\n".join(escaped_lines))

print("Escape V3 complete!")
